
import { NextResponse } from 'next/server';
import { activateUserSubscriptionAdmin } from '@/lib/firebase/firebase-admin';

export async function POST(request: Request) {
  try {
    const { uid } = await request.json();

    if (!uid) {
      return NextResponse.json({ error: 'User ID (uid) is required.' }, { status: 400 });
    }

    console.log(`[API_GRANT_ACCESS] Received request for UID: ${uid}`);
    await activateUserSubscriptionAdmin(uid);
    console.log(`[API_GRANT_ACCESS] Successfully granted access for UID: ${uid}`);
    
    return NextResponse.json({ success: true, message: `Subscription activated for user ${uid}.` });

  } catch (error) {
    console.error('[API_GRANT_ACCESS_FATAL] Error granting paid access:', error);
    const message = error instanceof Error ? error.message : 'An unknown server error occurred.';
    return NextResponse.json({ error: message }, { status: 500 });
  }
}
